    best_score = float('inf')

    for i, customer_pos in enumerate(unvisited_customers):
        travel_duration = travel_time(cur_truck_pos, customer_pos)
        arrival_time = current_time + travel_duration
        start_window, end_window = time_windows[i]

        if arrival_time > end_window:
            penalty = 1000 * (arrival_time - end_window)
        else:
            penalty = 0

        if arrival_time < start_window:
            wait_time = start_window - arrival_time
        else:
            wait_time = 0

        avg_travel_from_depot = np.mean([travel_time(depot_pos, truck_pos) for truck_pos in all_truck_pos])
        distribution_penalty = avg_travel_from_depot - travel_time(depot_pos, cur_truck_pos)

        score = (0.5 * travel_duration + penalty + wait_time + 0.5 * distribution_penalty)

        if score < best_score:
